            <h2 className="text-xl font-bold text-slate-100">{t.title}</h2>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={handleUndo} 
                disabled={history.length === 0}
                className={`flex items-center gap-2 px-3 py-1.5 text-xs font-medium border rounded transition-all ${
                    history.length > 0 
                    ? 'bg-slate-800 border-slate-700 text-slate-300 hover:text-white' 
                    : 'bg-slate-900 border-slate-800 text-slate-600 cursor-not-allowed'
                }`}
                title={t.undo}
            >
                <IconUndo className="w-3.5 h-3.5" />
                {t.undo}
            </button>
            <button 
                onClick={handleCopy} 
                className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium bg-slate-800 border border-slate-700 rounded text-slate-300 hover:text-white transition-all"
            >
                {copied ? <IconCheck className="w-3.5 h-3.5" /> : <IconCopy className="w-3.5 h-3.5" />}
                {copied ? t.copied : t.copy}
            </button>
            <button 
                onClick={handleClear}
                className="px-3 py-1.5 text-xs font-medium bg-red-900/20 border border-red-900/30 text-red-400 rounded hover:bg-red-900/30 transition-all"
            >
                {t.clear}
            </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col gap-4 min-h-0">
          {/* Action Toolbar - Optimized Grid Spans */}
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-12 gap-3">
              <button 
                onClick={handleUnescapeNewlines}
                className="xl:col-span-2 flex items-center justify-center gap-2 px-3 py-2 text-xs font-bold bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 rounded-lg transition-all"
              >
                <IconZap className="w-3.5 h-3.5 text-yellow-500" />
                {t.unescapeN}
              </button>

              <button 
                onClick={handleTrimLines}
                className="xl:col-span-2 px-3 py-2 text-xs font-bold bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 rounded-lg transition-all"
              >
                {t.trimLines}
              </button>

              {/* Quote Dropdown - Slightly wider for balance */}
              <div className="flex gap-1.5 xl:col-span-4">
                  <select 
                    value={quoteType}
                    onChange={(e) => setQuoteType(e.target.value)}
                    className="flex-1 min-w-0 bg-slate-800 border border-slate-700 rounded-lg px-2 py-2 text-xs text-slate-200 outline-none focus:ring-1 focus:ring-primary-500 appearance-none text-center font-mono cursor-pointer"
                  >
                      <option value='"'>" "</option>
                      <option value="'">' '</option>
                      <option value="`">` `</option>
                      <option value="[]">[ ]</option>
                      <option value="{}">{ }</option>
                      <option value="()"> ( ) </option>
                      <option value="<>">&lt; &gt;</option>
                  </select>
                  <button 
