const App: React.FC = () => {
  const [currentToolId, setCurrentToolId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); 
  const [isCollapsed, setIsCollapsed] = useState(true); 

  // Cache for tool states
  const [toolStates, setToolStates] = useState<Record<string, any>>({});

  const [lang, setLang] = useState<Lang>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  const t = {
    search: lang === 'zh' ? '搜索工具...' : 'Search tools...',
    home: lang === 'zh' ? '首页' : 'Home',
    welcome: lang === 'zh' ? '开发者工具箱' : 'Developer Utilities Hub',
    desc: lang === 'zh' ? '您的必备开发瑞士军刀。包含 JSON、Base64、正则、AI 助手等多种工具。' : 'Your essential Swiss Army knife for development. Privacy-first, client-side tools for everyday tasks.',
    [ToolCategory.DEVELOPER]: lang === 'zh' ? '开发' : 'Developer',
    [ToolCategory.CONVERTER]: lang === 'zh' ? '转换' : 'Converter',
    [ToolCategory.CRYPTO]: lang === 'zh' ? '加密' : 'Crypto',
    [ToolCategory.AI]: lang === 'zh' ? 'AI 助手' : 'AI Assistant',
    [ToolCategory.UTILITY]: lang === 'zh' ? '工具' : 'Utility',
  };

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const filteredTools = useMemo(() => {
    return TOOLS.filter(tool => {
        if (!searchTerm) return true;
        const toolName = lang === 'zh' ? tool.nameZh : tool.name;
        const toolDesc = lang === 'zh' ? tool.descriptionZh : tool.description;
        return (
            toolName.toLowerCase().includes(searchTerm.toLowerCase()) ||
            toolDesc.toLowerCase().includes(searchTerm.toLowerCase()) ||
            tool.keywords.some(k => k.toLowerCase().includes(searchTerm.toLowerCase()))
        );
    });
  }, [searchTerm, lang]);

  const groupedTools = useMemo<Record<string, ToolDef[]>>(() => {
    const groups: Record<string, ToolDef[]> = {};
    filteredTools.forEach(tool => {
        if (!groups[tool.category]) groups[tool.category] = [];
        groups[tool.category].push(tool);
    });
    return groups;
  }, [filteredTools]);

  const currentTool = TOOLS.find(t => t.id === currentToolId);

  const handleToolSelect = (id: string) => {
    setCurrentToolId(id);
    setIsSidebarOpen(false); 
    if (window.innerWidth < 768) {
        setSearchTerm('');
    }
  };

  const handleGoHome = () => {
    setCurrentToolId(null);
    setIsSidebarOpen(false);
  };

  const toggleCollapse = () => {
    setIsCollapsed(!isCollapsed);
  };

  const updateToolState = (id: string, newState: any) => {
    setToolStates(prev => ({ ...prev, [id]: newState }));
  };

  const isDesktopCollapsed = !isSidebarOpen && isCollapsed;

  // Flattened Navigation Helper
  const renderNavItem = (item: any, isHome = false) => {
    const isActive = isHome ? !currentToolId : currentToolId === item.id;
    const label = isHome ? t.home : (lang === 'zh' ? item.nameZh : item.name);
    const onClick = isHome ? handleGoHome : () => handleToolSelect(item.id);

    return (
        <button
            key={isHome ? 'home-nav' : item.id}
            onClick={onClick}
            title={label}
            className={`flex items-center rounded-md text-xs font-medium transition-all group shrink-0 ${
                isActive
                ? (isDesktopCollapsed ? 'bg-primary-600 text-white' : 'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400')
                : 'text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800'
            } ${isDesktopCollapsed ? 'w-12 h-10 justify-center gap-0 p-0' : 'w-full px-2 py-2 gap-3'}`}
        >
            <span className={`shrink-0 flex items-center justify-center transition-transform duration-200 group-hover:scale-110 ${isActive ? (isDesktopCollapsed ? 'text-white' : 'text-primary-500') : 'text-slate-400 group-hover:text-primary-500'}`}>
                {isHome ? <IconHome className="w-5 h-5" /> : item.icon}
            </span>
            <span className={`truncate transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0 overflow-hidden' : 'opacity-100'}`}>
                {label}
            </span>
        </button>
    );
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-200 overflow-hidden font-sans text-sm">

      {isSidebarOpen && (
          <div 
            className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm md:hidden animate-in fade-in duration-200"
            onClick={() => setIsSidebarOpen(false)}
          />
      )}

      <aside className={`
          fixed md:static inset-y-0 left-0 z-50 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex flex-col transition-all duration-300 ease-in-out shadow-2xl md:shadow-none
          ${isSidebarOpen ? 'w-64 translate-x-0' : '-translate-x-full md:translate-x-0'}
          ${isDesktopCollapsed ? 'md:w-16' : 'md:w-64'}
      `}>
          {/* Sidebar Header */}
          <div className={`flex items-center border-b border-slate-100 dark:border-slate-800 shrink-0 overflow-hidden transition-all duration-300 ${isDesktopCollapsed ? 'h-12 px-0 justify-center' : 'h-14 px-4'}`}>
             <div 
                className={`flex items-center cursor-pointer group transition-all duration-300 ${isDesktopCollapsed ? 'justify-center w-12 gap-0' : 'w-full gap-3'}`} 
                onClick={handleGoHome}
             >
                <div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md text-xs shrink-0">
                    NB
                </div>
                <span className={`text-base font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-700 to-slate-900 dark:from-slate-100 dark:to-slate-300 whitespace-nowrap transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0' : 'opacity-100'}`}>
                    NewBeTools
                </span>
             </div>

             {!isDesktopCollapsed && (
                <button onClick={toggleCollapse} className="ml-auto p-1.5 rounded-md text-slate-400 hover:text-primary-500 hover:bg-slate-100 dark:hover:bg-slate-800 transition-all">
                    <IconPanelLeft className="w-4 h-4 transform rotate-180" />
                </button>
             )}

             <button onClick={() => setIsSidebarOpen(false)} className="md:hidden ml-auto text-slate-400">
                 <IconX className="w-5 h-5" />
             </button>
          </div>

          <div className={`p-2 shrink-0 transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 h-0 p-0 overflow-hidden' : 'opacity-100 h-12'}`}>
             <div className="relative">
                <IconSearch className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
                <input 
                    type="text"
                    placeholder={t.search}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-slate-100 dark:bg-slate-800 border-none rounded-md py-1.5 pl-8 pr-3 text-xs text-slate-900 dark:text-slate-200 focus:ring-2 focus:ring-primary-500 placeholder:text-slate-500 transition-all"
                />
             </div>
          </div>

          {/* Collapsed Mode Toggler (Centered) */}
          {isDesktopCollapsed && (
              <div className="flex justify-center border-b border-slate-100 dark:border-slate-800 hidden md:flex w-full py-0.5">
                  <button onClick={toggleCollapse} className="w-12 h-10 flex items-center justify-center rounded-md hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-primary-500 transition-colors">
                      <IconMenu className="w-5 h-5" />
                  </button>
              </div>
          )}

          {/* Navigation Area */}
          <div className={`flex-1 overflow-y-auto py-1 transition-all duration-300 ${isDesktopCollapsed ? 'px-0 flex flex-col items-center gap-1' : 'px-2'}`}>

              {/* If collapsed, use a completely flat list for uniform spacing */}
              {isDesktopCollapsed ? (
                <>
                  {renderNavItem(null, true)}
                  {filteredTools.map(tool => renderNavItem(tool))}
                </>
              ) : (
                <>
                  {renderNavItem(null, true)}
                  <div className="w-full space-y-4">
                    {Object.entries(groupedTools).map(([cat, tools]) => (
                        <div key={cat} className="flex flex-col w-full">
                            <div className="px-2 mb-1 mt-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                                {t[cat as ToolCategory] || cat}
                            </div>
                            <div className="w-full space-y-0.5">
                                {tools.map(tool => renderNavItem(tool))}
                            </div>
                        </div>
                    ))}
                  </div>
                </>
              )}
          </div>

          {/* Sidebar Footer */}
          <div className={`p-2 border-t border-slate-100 dark:border-slate-800 shrink-0 flex transition-all duration-300 ${isDesktopCollapsed ? 'flex-col items-center gap-1 px-0 py-2' : 'gap-2'}`}>
               <button 
                  onClick={() => setLang(lang === 'zh' ? 'en' : 'zh')}
                  title={lang === 'zh' ? 'English' : '中文'}
                  className={`flex items-center justify-center rounded-md bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 text-xs font-medium transition-all ${isDesktopCollapsed ? 'w-12 h-10 gap-0' : 'flex-1 py-2 gap-2'}`}
               >
                  <IconLanguage className="w-4 h-4 shrink-0" />
                  <span className={`whitespace-nowrap transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0 overflow-hidden' : 'opacity-100'}`}>
                    {lang === 'zh' ? '中文' : 'EN'}
                  </span>
               </button>
               <button 
                  onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                  title={theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
                  className={`flex items-center justify-center rounded-md bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all ${isDesktopCollapsed ? 'w-12 h-10' : 'w-10 py-2'}`}
               >
                  {theme === 'dark' ? <IconSun className="w-4 h-4" /> : <IconMoon className="w-4 h-4" />}
               </button>
          </div>
      </aside>

      <div className="flex-1 flex flex-col h-full min-w-0">
         <header className="md:hidden h-10 bg-white/90 dark:bg-slate-900/90 backdrop-blur border-b border-slate-200 dark:border-slate-800 flex items-center px-4 gap-3 shrink-0 sticky top-0 z-30">
             <button onClick={() => setIsSidebarOpen(true)} className="p-1 -ml-1 text-slate-600 dark:text-slate-300">
                 <IconMenu className="w-5 h-5" />
             </button>
             <h1 className="font-bold text-slate-900 dark:text-white truncate text-sm">
                 {currentTool ? (lang === 'zh' ? currentTool.nameZh : currentTool.name) : 'NewBeTools'}
             </h1>
         </header>

         <main className="flex-1 overflow-auto p-2 md:p-4">
            <div className={`h-full flex flex-col ${currentTool ? 'w-full' : 'max-w-7xl mx-auto'}`}>
                {currentTool ? (
                    <div className="flex flex-col h-full animate-in fade-in slide-in-from-bottom-2 duration-300">
                         <div className="flex-1 min-h-0 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-4 shadow-sm overflow-hidden flex flex-col">
                             {React.isValidElement(currentTool.component) 
                                ? React.cloneElement(currentTool.component as React.ReactElement<any>, { 
                                    lang,
                                    state: toolStates[currentTool.id],
                                    onStateChange: (s: any) => updateToolState(currentTool.id, s)
                                  }) 
                                : currentTool.component}
                         </div>
                    </div>
                ) : (
                    <div className="space-y-6 pb-6">
                        <div className="text-center py-6 md:py-10 space-y-3">
                            <div className="inline-flex p-3 rounded-xl bg-gradient-to-br from-primary-500/10 to-indigo-500/10 mb-2">
                                <div className="w-12 h-12 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-lg">
                                    NB
                                </div>
                            </div>
                            <h1 className="text-2xl md:text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">
                                {t.welcome}
                            </h1>
                            <p className="text-slate-500 dark:text-slate-400 text-sm max-w-xl mx-auto leading-relaxed">
                                {t.desc}
                            </p>
                        </div>

                        {Object.entries(groupedTools).length > 0 ? (Object.entries(groupedTools) as [string, ToolDef[]][]).map(([cat, tools]) => (
                            <div key={cat} className="space-y-3">
                                <div className="flex items-center gap-2 border-b border-slate-200 dark:border-slate-800 pb-1.5">
                                    <h3 className="text-sm font-bold text-slate-700 dark:text-slate-200">
                                        {t[cat as ToolCategory] || cat}
                                    </h3>
                                    <span className="text-[10px] bg-slate-100 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded-full">
                                        {tools.length}
                                    </span>
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                                    {tools.map(tool => (
                                        <ToolCard 
                                            key={tool.id} 
                                            tool={tool} 
                                            onClick={handleToolSelect} 
                                            lang={lang} 
                                        />
                                    ))}
                                </div>
                            </div>
                        )) : (
                            <div className="text-center text-slate-500 py-20">
                                <p className="italic">{lang === 'zh' ? '没有找到相关工具' : 'No tools matching your search'}</p>
                            </div>
                        )}
                    </div>
                )}
            </div>
         </main>
      </div>

    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { IconCopy, IconCheck, IconX, IconSearch, IconJson, IconType, IconPanelLeft, IconEraser, IconSparkles, IconDiff } from '../Icons';
import { ToolComponentProps } from '../../types';

// Access global jsonpath object from CDN
declare const jsonpath: any;

// --- Helper Components ---

interface JsonEditorProps {
  value: string;
  onChange: (value: string) => void;
  error: boolean;
  placeholder?: string;
}

const JsonEditor: React.FC<JsonEditorProps> = ({ value, onChange, error, placeholder }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const preRef = useRef<HTMLPreElement>(null);

  // 同步滚动
  const handleScroll = () => {
    if (textareaRef.current && preRef.current) {
      preRef.current.scrollTop = textareaRef.current.scrollTop;
      preRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  const highlighted = useMemo(() => {
    if (!value) return '';
    // 转义 HTML
    const safeHtml = value.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    // JSON 语法高亮逻辑
    return safeHtml.replace(
      /("(\\u[a-zA-Z0-9]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+\-]?\d+)?)/g,
      (match) => {
        let cls = 'text-amber-400'; // 数字
        if (/^"/.test(match)) {
          if (/:$/.test(match)) {
            cls = 'text-sky-400 font-semibold'; // 键名
          } else {
            cls = 'text-emerald-400'; // 字符串
          }
        } else if (/true|false/.test(match)) {
          cls = 'text-violet-400 font-semibold'; // 布尔
        } else if (/null/.test(match)) {
          cls = 'text-slate-500 italic'; // Null
        }
        return `<span class="${cls}">${match}</span>`;
      }
    );
  }, [value]);

  // 极致精确的共享样式
  const sharedStyles: React.CSSProperties = {
    fontFamily: 'Menlo, Monaco, "Courier New", monospace',
    fontSize: '13px',
    lineHeight: '20px',
    padding: '16px', // 对应 p-4
    margin: 0,
    whiteSpace: 'pre-wrap',
    wordBreak: 'break-all',
    boxSizing: 'border-box',
    tabSize: 2,
    letterSpacing: '0px',
    fontVariantLigatures: 'none',
    border: 'none',
    outline: 'none',
  };

  return (
    <div className="relative w-full h-full bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
      <style>{`
        .editor-stack {
          display: grid;
          grid-template-columns: 1fr;
          grid-template-rows: 1fr;
          width: 100%;
          height: 100%;
        }

        .editor-stack textarea, 
        .editor-stack pre {
          grid-area: 1 / 1 / 2 / 2;
          width: 100% !important;
          height: 100% !important;
          overflow-y: scroll !important;
          scrollbar-width: none;
          -ms-overflow-style: none;
        }

        .editor-stack textarea::-webkit-scrollbar,
        .editor-stack pre::-webkit-scrollbar {
          display: none;
        }

        .editor-stack textarea {
          background: transparent !important;
          color: transparent !important;
          -webkit-text-fill-color: transparent !important;
          caret-color: white !important;
          z-index: 2;
        }

        .editor-stack textarea::selection {
          background: rgba(59, 130, 246, 0.4) !important;
          -webkit-text-fill-color: transparent !important;
        }

        .editor-stack pre {
          z-index: 1;
          background: transparent !important;
          pointer-events: none;
          user-select: none;
        }
      `}</style>

      <div className="editor-stack">
        <pre 
          ref={preRef}
          style={sharedStyles}
          className="m-0 text-slate-200"
          aria-hidden="true"
          dangerouslySetInnerHTML={{ __html: highlighted + (value.endsWith('\n') ? ' ' : '') }} 
        />
        <textarea
          ref={textareaRef}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onScroll={handleScroll}
          spellCheck="false"
          placeholder={placeholder}
          style={sharedStyles}
          className={`resize-none ${error ? 'focus:ring-2 focus:ring-red-500/20' : 'focus:ring-2 focus:ring-primary-500/20'}`}
        />
      </div>
    </div>
  );
};

// --- Tree View Components ---

interface JsonNodeProps {
  name?: string;
  value: any;
  isLast: boolean;
}

const JsonNode: React.FC<JsonNodeProps> = ({ name, value, isLast }) => {
  const [collapsed, setCollapsed] = useState(false);

  const isObject = value !== null && typeof value === 'object';
  const isArray = Array.isArray(value);
  const isEmpty = isObject && Object.keys(value).length === 0;

  if (!isObject) {
    const color = typeof value === 'string' ? 'text-green-400' 
                : typeof value === 'number' ? 'text-blue-400' 
                : typeof value === 'boolean' ? 'text-purple-400' 
                : 'text-slate-400';

    return (
      <div className="hover:bg-slate-800/50 px-1 rounded font-mono text-sm leading-6 ml-4">
        {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
        <span className={color}>{JSON.stringify(value)}</span>
        {!isLast && <span className="text-slate-500">,</span>}
      </div>
    );
  }

  const keys = Object.keys(value);
  const openBracket = isArray ? '[' : '{';
  const closeBracket = isArray ? ']' : '}';

  if (isEmpty) {
     return (
       <div className="hover:bg-slate-800/50 px-1 rounded font-mono text-sm leading-6 ml-4">
         {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
         <span className="text-slate-500">{openBracket}{closeBracket}</span>
         {!isLast && <span className="text-slate-500">,</span>}
       </div>
     );
  }

  return (
    <div className="group font-mono text-sm leading-6">
       <div className="hover:bg-slate-800/50 px-1 rounded flex items-start">
         <button 
            onClick={(e) => { e.stopPropagation(); setCollapsed(!collapsed); }} 
            className="w-4 h-6 flex items-center justify-center text-slate-500 hover:text-slate-300 mr-0.5 select-none shrink-0"
         >
            <span className="text-[9px] transform transition-transform duration-200" style={{ transform: collapsed ? 'rotate(-90deg)' : 'rotate(0deg)' }}>▼</span>
         </button>

         <div className="flex-1 min-w-0">
            {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
            <span className="text-slate-500">{openBracket}</span>

            {collapsed ? (
                <>
                  <button onClick={() => setCollapsed(false)} className="text-slate-600 text-[10px] px-1.5 hover:text-slate-400 select-none bg-slate-700/50 rounded mx-1">...</button>
                  <span className="text-slate-500">{closeBracket}</span>
                  {!isLast && <span className="text-slate-500">,</span>}
                  <span className="text-slate-600 ml-2 text-xs italic">// {isArray ? `${keys.length} items` : `${keys.length} keys`}</span>
                </>
            ) : (
                <>
                   <div className="pl-3 border-l border-slate-700/50 ml-1.5 my-0.5">
                        {keys.map((key, idx) => (
                            <JsonNode 
                                key={key} 
                                name={isArray ? undefined : key} 
                                value={value[key]} 
                                isLast={idx === keys.length - 1} 
                            />
                        ))}
                    </div>
                    <div className="ml-4">
                      <span className="text-slate-500">{closeBracket}</span>
                      {!isLast && <span className="text-slate-500">,</span>}
                    </div>
                </>
            )}
         </div>
       </div>
    </div>
  );
};

const JsonFormatter: React.FC<ToolComponentProps> = ({ lang, state, onStateChange }) => {
  // Use persistent state if available
  const [input, setInput] = useState(state?.input || '');
  const [viewMode, setViewMode] = useState<'text' | 'tree' | 'split'>(state?.viewMode || 'split');
  const [showJsonPath, setShowJsonPath] = useState(state?.showJsonPath || false);
  const [pathQuery, setPathQuery] = useState(state?.pathQuery || '$.');

  const [error, setError] = useState<string | null>(null);
  const [errorVisible, setErrorVisible] = useState(false);
  const [copied, setCopied] = useState(false);
  const [pathResult, setPathResult] = useState('');

  // Sync state back to parent
  useEffect(() => {
    onStateChange?.({ input, viewMode, showJsonPath, pathQuery });
  }, [input, viewMode, showJsonPath, pathQuery, onStateChange]);

  const t = {
    title: lang === 'zh' ? 'JSON 编辑器' : 'JSON Editor',
    textMode: lang === 'zh' ? '文本' : 'Text',
    treeMode: lang === 'zh' ? '树形' : 'Tree',
    splitMode: lang === 'zh' ? '对照' : 'Split',
    path: lang === 'zh' ? '路径' : 'Path',
    esc: lang === 'zh' ? '转义' : 'Esc',
    unesc: lang === 'zh' ? '去转义' : 'UnEsc',
    rmNewline: lang === 'zh' ? '去除 \\n' : 'Del \\n',
    fix: lang === 'zh' ? '自动修复' : 'Auto Fix',
    format: lang === 'zh' ? '格式化' : 'Format',
    minify: lang === 'zh' ? '压缩' : 'Minify',
    copy: lang === 'zh' ? '复制' : 'Copy',
    copied: lang === 'zh' ? '已复制' : 'Copied',
    inputTitle: lang === 'zh' ? '输入 JSON' : 'Input JSON',
    treeTitle: lang === 'zh' ? '树形视图' : 'Tree Viewer',
    pathTitle: lang === 'zh' ? 'JSONPath 表达式' : 'JSONPath Expression',
    resultTitle: lang === 'zh' ? '提取结果' : 'Extraction Result',
    readonly: lang === 'zh' ? '只读' : 'ReadOnly',
    placeholder: lang === 'zh' ? '在此粘贴或输入 JSON...' : 'Paste or type JSON here...',
    empty: lang === 'zh' ? '无效的 JSON - 请在文本模式修复错误。' : 'Invalid JSON - switch to Text mode to fix errors.',
    noMatch: lang === 'zh' ? '无匹配' : 'No match',
  };

  useEffect(() => {
    if (!input.trim()) {
      setError(null);
      setErrorVisible(false);
      return;
    }
    try {
      JSON.parse(input);
      setError(null);
      setErrorVisible(false);
    } catch (e: any) {
      setError(e.message);
      setErrorVisible(true);
    }
  }, [input]);

  useEffect(() => {
    if (errorVisible) {
        const timer = setTimeout(() => setErrorVisible(false), 3000);
        return () => clearTimeout(timer);
    }
  }, [errorVisible]);

  useEffect(() => {
    if (!input.trim() || !pathQuery.trim() || error || typeof jsonpath === 'undefined') {
        setPathResult('');
        return;
    }
    try {
        const jsonData = JSON.parse(input);
        const result = jsonpath.query(jsonData, pathQuery);
        setPathResult(result.length === 0 ? t.noMatch : JSON.stringify(result, null, 2));
    } catch {
        setPathResult('');
    }
  }, [input, pathQuery, error, t.noMatch]);

  const formatJson = () => {
    try {
      const parsed = JSON.parse(input);
      setInput(JSON.stringify(parsed, null, 2));
      setError(null);
      setErrorVisible(false);
    } catch (e: any) {
      setError(e.message);
      setErrorVisible(true);
    }
  };

  const minifyJson = () => {
    try {
      const parsed = JSON.parse(input);
      setInput(JSON.stringify(parsed));
      setError(null);
      setErrorVisible(false);
    } catch (e: any) {
      setError(e.message);
      setErrorVisible(true);
    }
  };

  const escapeJson = () => {
    setInput(JSON.stringify(input));
  };

  const unescapeJson = () => {
      try {
          if (input.startsWith('"') && input.endsWith('"')) {
              setInput(JSON.parse(input));
          } else {
              setInput(input.replace(/\\"/g, '"').replace(/\\\\/g, '\\'));
          }
      } catch(e: any) {
          setError(e.message);
          setErrorVisible(true);
      }
  };

  const removeNewlines = () => {
    setInput(input.replace(/\\n/g, ''));
  };

  const fixJson = () => {
    let fixed = input.replace(/\\'/g, "'").replace(/\bNone\b/g, 'null').replace(/\bTrue\b/g, 'true').replace(/\bFalse\b/g, 'false').replace(/,\s*([\]}])/g, '$1');
    try {
        const parsed = JSON.parse(fixed);
        setInput(JSON.stringify(parsed, null, 2));
        setError(null);
        setErrorVisible(false);
    } catch {
        setInput(fixed);
    }
  };

  const handleCopy = (text: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const parsedJson = useMemo(() => {
      if (!input.trim()) return null;
      try { return JSON.parse(input); } catch { return null; }
  }, [input]);

  const showText = viewMode === 'text' || viewMode === 'split';
  const showTree = viewMode === 'tree' || viewMode === 'split';

  return (
    <div className="flex flex-col gap-4 h-full min-h-[500px]">
      <div className="flex flex-wrap items-center justify-between gap-3 p-1">
        <div className="flex items-center gap-2">
            <IconJson className="w-5 h-5 text-primary-400" />
            <h2 className="text-lg font-bold text-slate-100">{t.title}</h2>
        </div>
        <div className="flex flex-wrap gap-2 items-center">
            {/* 格式化按钮 */}
            <button 
              onClick={formatJson} 
              className="px-4 py-1.5 text-xs font-bold bg-primary-600 hover:bg-primary-500 rounded text-white transition-colors shadow-md mr-1"
            >
              {t.format}
            </button>

            {/* 视图模式组 */}
            <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700 mr-1">
                <button 
                    onClick={() => setViewMode('text')} 
                    className={`px-3 py-1 text-xs font-medium rounded transition-all flex items-center gap-1.5 ${viewMode === 'text' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                    title={t.textMode}
                >
                    <IconType className="w-3.5 h-3.5" />
                    <span className="hidden sm:inline">{t.textMode}</span>
                </button>
                <button 
                    onClick={() => setViewMode('tree')} 
                    className={`px-3 py-1 text-xs font-medium rounded transition-all flex items-center gap-1.5 ${viewMode === 'tree' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                    title={t.treeMode}
                >
                    <IconPanelLeft className="w-3.5 h-3.5" />
                    <span className="hidden sm:inline">{t.treeMode}</span>
                </button>
                <button 
                    onClick={() => setViewMode('split')} 
                    className={`px-3 py-1 text-xs font-medium rounded transition-all flex items-center gap-1.5 ${viewMode === 'split' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                    title={t.splitMode}
                >
                    <IconDiff className="w-3.5 h-3.5" />
                    <span className="hidden sm:inline">{t.splitMode}</span>
                </button>
            </div>

            <button 
                onClick={() => setShowJsonPath(!showJsonPath)} 
                className={`px-3 py-1.5 text-xs font-medium rounded border transition-colors flex items-center gap-2 ${showJsonPath ? 'bg-primary-900/30 border-primary-500/50 text-primary-300' : 'bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700'}`}
            >
                <IconSearch className="w-3 h-3" /> {t.path}
            </button>

            <div className="w-px h-6 bg-slate-700 mx-1 hidden lg:block"></div>

            <div className="flex gap-1">
                 <button onClick={escapeJson} className="px-2 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300">{t.esc}</button>
                 <button onClick={unescapeJson} className="px-2 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300">{t.unesc}</button>
                 <button onClick={removeNewlines} className="px-2 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300">{t.rmNewline}</button>
                 <button onClick={fixJson} className="px-2 py-1.5 text-xs font-medium bg-indigo-900/30 hover:bg-indigo-900/50 text-indigo-300 rounded border border-indigo-900/50 flex items-center gap-1">
                    <IconSparkles className="w-3 h-3" /> {t.fix}
                 </button>
            </div>

            <button onClick={minifyJson} className="px-3 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300 transition-colors ml-1">{t.minify}</button>
        </div>
      </div>

      <div className="flex-1 flex flex-col md:flex-row gap-4 min-h-0">
        {/* 主要显示区域 */}
        <div className={`flex-1 flex flex-col gap-3 min-w-0 h-full ${viewMode === 'split' ? 'lg:flex-row' : ''}`}>

            {/* 文本编辑器 */}
            {showText && (
                <div className="flex-1 flex flex-col gap-1.5 min-w-0 h-full relative group">
                    <div className="flex justify-between items-center px-1 h-6 shrink-0">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.inputTitle}</span>
                        <button onClick={() => handleCopy(input)} className="text-xs flex items-center gap-1 text-slate-500 hover:text-primary-400 transition-colors h-full">
                            {copied ? <IconCheck className="w-3 h-3"/> : <IconCopy className="w-3 h-3"/>} {t.copy}
                        </button>
                    </div>

                    <div className="flex-1 min-h-0">
                        <JsonEditor value={input} onChange={setInput} error={!!error} placeholder={t.placeholder} />
                    </div>

                    {error && errorVisible && (
                        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-30 w-[90%] max-w-md">
                            <div className="bg-red-600 text-white px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in zoom-in-95 duration-200">
                                <IconX className="w-5 h-5 shrink-0" />
                                <span className="flex-1 truncate font-mono text-xs">{error}</span>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* 树形视图 */}
            {showTree && (
                <div className="flex-1 flex flex-col gap-1.5 min-w-0 h-full">
                    <div className="flex justify-between items-center px-1 h-6 shrink-0">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.treeTitle}</span>
                        <span className="text-[10px] text-slate-600 uppercase tracking-tight">Interactive</span>
                    </div>
                    <div className="flex-1 h-full overflow-hidden bg-slate-800 rounded-xl border border-slate-700">
                        <div className="w-full h-full overflow-auto p-4">
                            {parsedJson ? <JsonNode value={parsedJson} isLast={true} /> : <div className="text-slate-500 italic text-sm">{input.trim() ? t.empty : (lang === 'zh' ? '空数据' : 'Empty Data')}</div>}
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* JSONPath 面板 */}
        {showJsonPath && (
            <div className="flex-1 md:flex-[0.8] lg:flex-[0.6] xl:flex-[0.5] flex flex-col gap-3 min-w-0 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="flex flex-col gap-1.5 shrink-0">
                    <div className="flex items-center gap-2 px-1 h-6">
                        <IconSearch className="w-3 h-3 text-slate-400" />
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.pathTitle}</span>
                    </div>
                    <input type="text" value={pathQuery} onChange={(e) => setPathQuery(e.target.value)} placeholder="$.store.book[*]" className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 px-3 text-slate-200 font-mono text-sm focus:ring-2 focus:ring-primary-500 outline-none" />
                </div>
                <div className="flex-1 flex flex-col gap-1.5 min-h-0">
                    <div className="flex justify-between items-center px-1 h-6">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.resultTitle}</span>
                        <span className="text-xs text-slate-600 uppercase tracking-tighter">{t.readonly}</span>
                    </div>
                    <div className="flex-1 relative bg-slate-900 rounded-xl border border-slate-800 overflow-hidden">
                        <textarea readOnly value={pathResult} className={`absolute inset-0 w-full h-full bg-transparent p-4 font-mono text-xs sm:text-sm resize-none outline-none ${pathResult === t.noMatch ? 'text-slate-500 italic' : 'text-green-400'}`} placeholder={lang === 'zh' ? '结果将显示在这里...' : "Results will appear here..."} />
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

