];

const App: React.FC = () => {
  const [currentToolId, setCurrentToolId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); 
  const [isCollapsed, setIsCollapsed] = useState(true); 
  const [toolStates, setToolStates] = useState<Record<string, any>>({});
  const [lang, setLang] = useState<Lang>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  const updateToolState = useCallback((id: string, newState: any) => {
    setToolStates(prev => {
        // Only update if reference or value changed to prevent infinite loops
        if (prev[id] === newState) return prev;
        return { ...prev, [id]: newState };
    });
  }, []);

  const handleCurrentToolStateChange = useCallback((newState: any) => {
      if (currentToolId) {
          updateToolState(currentToolId, newState);
      }
  }, [currentToolId, updateToolState]);

  const t = {
    search: lang === 'zh' ? '搜索工具...' : 'Search tools...',
    home: lang === 'zh' ? '首页' : 'Home',
    welcome: lang === 'zh' ? '开发者工具箱' : 'Developer Utilities Hub',
    desc: lang === 'zh' ? '您的必备开发瑞士军刀。包含 JSON、Base64、正则、AI 助手等多种工具。' : 'Your essential Swiss Army knife for development. Privacy-first, client-side tools for everyday tasks.',
    [ToolCategory.DEVELOPER]: lang === 'zh' ? '开发' : 'Developer',
    [ToolCategory.CONVERTER]: lang === 'zh' ? '转换' : 'Converter',
    [ToolCategory.CRYPTO]: lang === 'zh' ? '加密' : 'Crypto',
    [ToolCategory.AI]: lang === 'zh' ? 'AI 助手' : 'AI Assistant',
    [ToolCategory.UTILITY]: lang === 'zh' ? '工具' : 'Utility',
  };

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const filteredTools = useMemo(() => {
    return TOOLS.filter(tool => {
        if (!searchTerm) return true;
        const toolName = lang === 'zh' ? tool.nameZh : tool.name;
        const toolDesc = lang === 'zh' ? tool.descriptionZh : tool.description;
        return (
            toolName.toLowerCase().includes(searchTerm.toLowerCase()) ||
            toolDesc.toLowerCase().includes(searchTerm.toLowerCase()) ||
            tool.keywords.some(k => k.toLowerCase().includes(searchTerm.toLowerCase()))
        );
    });
  }, [searchTerm, lang]);

  const groupedTools = useMemo<Record<string, ToolDef[]>>(() => {
    const groups: Record<string, ToolDef[]> = {};
    filteredTools.forEach(tool => {
        if (!groups[tool.category]) groups[tool.category] = [];
        groups[tool.category].push(tool);
    });
    return groups;
  }, [filteredTools]);

  const currentTool = TOOLS.find(t => t.id === currentToolId);

  const handleToolSelect = (id: string) => {
    setCurrentToolId(id);
    setIsSidebarOpen(false); 
    if (window.innerWidth < 768) {
        setSearchTerm('');
    }
  };

  const handleGoHome = () => {
    setCurrentToolId(null);
    setIsSidebarOpen(false);
  };

  const toggleCollapse = () => {
    setIsCollapsed(!isCollapsed);
  };

  const isDesktopCollapsed = !isSidebarOpen && isCollapsed;

  const renderNavItem = (item: any, isHome = false) => {
    const isActive = isHome ? !currentToolId : currentToolId === item.id;
    const label = isHome ? t.home : (lang === 'zh' ? item.nameZh : item.name);
    const onClick = isHome ? handleGoHome : () => handleToolSelect(item.id);

    return (
        <button
            key={isHome ? 'home-nav' : item.id}
            onClick={onClick}
            title={label}
            className={`flex items-center rounded-md text-xs font-medium transition-all group shrink-0 ${
                isActive
                ? (isDesktopCollapsed ? 'bg-primary-600 text-white shadow-lg' : 'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400')
                : 'text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800'
            } ${isDesktopCollapsed ? 'w-12 h-12 justify-center gap-0 p-0' : 'w-full px-2 py-2 gap-3'}`}
        >
            <span className={`shrink-0 flex items-center justify-center transition-transform duration-200 group-hover:scale-110 ${isActive ? (isDesktopCollapsed ? 'text-white' : 'text-primary-500') : 'text-slate-400 group-hover:text-primary-500'}`}>
                {isHome ? <IconHome className="w-5 h-5" /> : item.icon}
            </span>
            <span className={`truncate transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0 overflow-hidden' : 'opacity-100'}`}>
                {label}
            </span>
        </button>
    );
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-200 overflow-hidden font-sans text-sm">

      {isSidebarOpen && (
          <div 
            className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm md:hidden animate-in fade-in duration-200"
            onClick={() => setIsSidebarOpen(false)}
          />
      )}

      <aside className={`
          fixed md:static inset-y-0 left-0 z-50 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex flex-col transition-all duration-300 ease-in-out shadow-2xl md:shadow-none
          ${isSidebarOpen ? 'w-64 translate-x-0' : '-translate-x-full md:translate-x-0'}
          ${isDesktopCollapsed ? 'md:w-16' : 'md:w-64'}
      `}>
          <div className={`flex items-center border-b border-slate-100 dark:border-slate-800 shrink-0 overflow-hidden transition-all duration-300 ${isDesktopCollapsed ? 'h-14 px-0 justify-center' : 'h-14 px-4'}`}>
             <div 
                className={`flex items-center cursor-pointer group transition-all duration-300 ${isDesktopCollapsed ? 'justify-center w-12 gap-0' : 'w-full gap-3'}`} 
                onClick={handleGoHome}
             >
                <div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md text-xs shrink-0">
                    NB
                </div>
                <span className={`text-base font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-700 to-slate-900 dark:from-slate-100 dark:to-slate-300 whitespace-nowrap transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0' : 'opacity-100'}`}>
                    NewBeTools
                </span>
             </div>

             {!isDesktopCollapsed && (
                <button onClick={toggleCollapse} className="ml-auto p-1.5 rounded-md text-slate-400 hover:text-primary-500 hover:bg-slate-100 dark:hover:bg-slate-800 transition-all">
                    <IconPanelLeft className="w-4 h-4 transform rotate-180" />
                </button>
             )}

             <button onClick={() => setIsSidebarOpen(false)} className="md:hidden ml-auto text-slate-400">
                 <IconX className="w-5 h-5" />
             </button>
          </div>

          {isDesktopCollapsed && (
              <div className="flex justify-center border-b border-slate-100 dark:border-slate-800 hidden md:flex w-full py-2">
                  <button onClick={toggleCollapse} className="w-12 h-12 flex items-center justify-center rounded-md hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-primary-500 transition-colors">
                      <IconMenu className="w-5 h-5" />
                  </button>
              </div>
          )}

          <div className={`p-2 shrink-0 transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 h-0 p-0 overflow-hidden' : 'opacity-100 h-12'}`}>
             <div className="relative">
                <IconSearch className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
                <input 
                    type="text"
                    placeholder={t.search}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-slate-100 dark:bg-slate-800 border-none rounded-md py-1.5 pl-8 pr-3 text-xs text-slate-900 dark:text-slate-200 focus:ring-2 focus:ring-primary-500 placeholder:text-slate-500 transition-all"
                />
             </div>
          </div>

          <div className={`flex-1 overflow-y-auto py-1 transition-all duration-300 ${isDesktopCollapsed ? 'px-0 flex flex-col items-center gap-1.5' : 'px-2'}`}>
              {isDesktopCollapsed ? (
                <>
                  {renderNavItem(null, true)}
                  {filteredTools.map(tool => renderNavItem(tool))}
                </>
              ) : (
                <>
                  {renderNavItem(null, true)}
                  <div className="w-full space-y-4">
                    {Object.entries(groupedTools).map(([cat, tools]) => (
                        <div key={cat} className="flex flex-col w-full">
                            <div className="px-2 mb-1 mt-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                                {t[cat as ToolCategory] || cat}
                            </div>
                            <div className="w-full space-y-0.5">
                                {tools.map(tool => renderNavItem(tool))}
                            </div>
                        </div>
                    ))}
                  </div>
                </>
              )}
          </div>

          <div className={`p-2 border-t border-slate-100 dark:border-slate-800 shrink-0 flex transition-all duration-300 ${isDesktopCollapsed ? 'flex-col items-center gap-2 px-0 py-3' : 'gap-2'}`}>
               <button 
                  onClick={() => setLang(lang === 'zh' ? 'en' : 'zh')}
                  title={lang === 'zh' ? 'English' : '中文'}
                  className={`flex items-center justify-center rounded-md bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 text-xs font-medium transition-all ${isDesktopCollapsed ? 'w-12 h-12 gap-0' : 'flex-1 py-2 gap-2'}`}
               >
                  <IconLanguage className="w-4 h-4 shrink-0" />
                  <span className={`whitespace-nowrap transition-all duration-300 ${isDesktopCollapsed ? 'opacity-0 w-0 overflow-hidden' : 'opacity-100'}`}>
                    {lang === 'zh' ? '中文' : 'EN'}
                  </span>
               </button>
               <button 
                  onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                  title={theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
                  className={`flex items-center justify-center rounded-md bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all ${isDesktopCollapsed ? 'w-12 h-12' : 'w-10 py-2'}`}
               >
                  {theme === 'dark' ? <IconSun className="w-4 h-4" /> : <IconMoon className="w-4 h-4" />}
               </button>
          </div>
      </aside>

      <div className="flex-1 flex flex-col h-full min-w-0">
         <header className="md:hidden h-10 bg-white/90 dark:bg-slate-900/90 backdrop-blur border-b border-slate-200 dark:border-slate-800 flex items-center px-4 gap-3 shrink-0 sticky top-0 z-30">
             <button onClick={() => setIsSidebarOpen(true)} className="p-1 -ml-1 text-slate-600 dark:text-slate-300">
                 <IconMenu className="w-5 h-5" />
             </button>
             <h1 className="font-bold text-slate-900 dark:text-white truncate text-sm">
                 {currentTool ? (lang === 'zh' ? currentTool.nameZh : currentTool.name) : 'NewBeTools'}
             </h1>
         </header>

         <main className="flex-1 overflow-auto p-2 md:p-4">
            <div className={`h-full flex flex-col ${currentTool ? 'w-full' : 'max-w-7xl mx-auto'}`}>
                {currentTool ? (
                    <div className="flex flex-col h-full animate-in fade-in slide-in-from-bottom-2 duration-300">
                         <div className="flex-1 min-h-0 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-4 shadow-sm overflow-hidden flex flex-col">
                             {React.isValidElement(currentTool.component) 
                                ? React.cloneElement(currentTool.component as React.ReactElement<any>, { 
                                    lang,
                                    state: toolStates[currentTool.id],
                                    onStateChange: handleCurrentToolStateChange
                                  }) 
                                : currentTool.component}
                         </div>
                    </div>
                ) : (
                    <div className="space-y-6 pb-6">
                        <div className="text-center py-6 md:py-10 space-y-3">
                            <div className="inline-flex p-3 rounded-xl bg-gradient-to-br from-primary-500/10 to-indigo-500/10 mb-2">
                                <div className="w-12 h-12 bg-gradient-to-br from-primary-500 to-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-lg">
                                    NB
                                </div>
                            </div>
                            <h1 className="text-2xl md:text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">
                                {t.welcome}
                            </h1>
                            <p className="text-slate-500 dark:text-slate-400 text-sm max-w-xl mx-auto leading-relaxed">
                                {t.desc}
                            </p>
                        </div>

                        {Object.entries(groupedTools).length > 0 ? (Object.entries(groupedTools) as [string, ToolDef[]][]).map(([cat, tools]) => (
                            <div key={cat} className="space-y-3">
                                <div className="flex items-center gap-2 border-b border-slate-200 dark:border-slate-800 pb-1.5">
                                    <h3 className="text-sm font-bold text-slate-700 dark:text-slate-200">
                                        {t[cat as ToolCategory] || cat}
                                    </h3>
                                    <span className="text-[10px] bg-slate-100 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded-full">
                                        {tools.length}
                                    </span>
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                                    {tools.map(tool => (
                                        <ToolCard 
                                            key={tool.id} 
                                            tool={tool} 
                                            onClick={handleToolSelect} 
                                            lang={lang} 
                                        />
                                    ))}
                                </div>
                            </div>
                        )) : (
                            <div className="text-center text-slate-500 py-20">
                                <p className="italic">{lang === 'zh' ? '没有找到相关工具' : 'No tools matching your search'}</p>
                            </div>
                        )}
                    </div>
                )}
            </div>
         </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { IconCopy, IconCheck, IconType, IconZap, IconUndo, IconChevronDown, IconMarkdown, IconCode } from '../Icons';
import { ToolComponentProps } from '../../types';

// Access global marked object from CDN
declare const marked: any;

const TextProcessor: React.FC<ToolComponentProps> = ({ lang, state, onStateChange }) => {
  const [input, setInput] = useState(state?.input || '');
  const [debouncedInput, setDebouncedInput] = useState(state?.input || '');
  const [extraContent, setExtraContent] = useState(state?.extraContent || '');
  const [quoteType, setQuoteType] = useState(state?.quoteType || '"');
  const [history, setHistory] = useState<string[]>(state?.history || []);
  const [isPreview, setIsPreview] = useState(state?.isPreview || false);
  const [copied, setCopied] = useState(false);

  // Track the last state sent to parent to avoid infinite loop
  const lastReportedState = useRef<string>('');

  // Debounce Markdown Input
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedInput(input);
    }, 300);
    return () => clearTimeout(timer);
  }, [input]);

  // Sync state back to parent ONLY when it truly changes
  useEffect(() => {
    const nextState = { input, extraContent, quoteType, history, isPreview };
    const stateStr = JSON.stringify(nextState);

    if (lastReportedState.current !== stateStr) {
        lastReportedState.current = stateStr;
        onStateChange?.(nextState);
    }
  }, [input, extraContent, quoteType, history, isPreview, onStateChange]);

  const t = {
    title: lang === 'zh' ? '文本处理增强' : 'Text Processor Plus',
    copy: lang === 'zh' ? '复制' : 'Copy',
    copied: lang === 'zh' ? '已复制' : 'Copied',
    placeholder: lang === 'zh' ? '在此输入或粘贴需要处理的文本...' : 'Enter or paste text to process here...',
    unescapeN: lang === 'zh' ? '转义 \\n' : 'Unescape \\n',
    unescapeQ: lang === 'zh' ? '去除 \\"' : 'Unescape \\"',
    appendPrefix: lang === 'zh' ? '行首' : 'Pre',
    appendSuffix: lang === 'zh' ? '行尾' : 'Suf',
    extraPh: lang === 'zh' ? '添加内容...' : 'Content to add...',
    clear: lang === 'zh' ? '清空' : 'Clear',
    trimLines: lang === 'zh' ? '修剪空格' : 'Trim Lines',
    undo: lang === 'zh' ? '撤销' : 'Undo',
    wrap: lang === 'zh' ? '包裹' : 'Wrap',
    preview: lang === 'zh' ? '预览' : 'Preview',
    editor: lang === 'zh' ? '编辑' : 'Editor',
  };

  const saveToHistory = () => {
    setHistory(prev => [...prev.slice(-19), input]);
  };

  const handleUnescapeNewlines = () => {
    saveToHistory();
    setInput(input.replace(/\\n/g, '\n'));
  };

  const handleUnescapeQuotes = () => {
    saveToHistory();
    setInput(input.replace(/\\"/g, '"'));
  };

  const handleQuoteLines = () => {
    saveToHistory();
    let start = quoteType, end = quoteType;
    if (quoteType === '[]') { start = '['; end = ']'; }
    else if (quoteType === '{}') { start = '{'; end = '}'; }
    else if (quoteType === '()') { start = '('; end = ')'; }
    else if (quoteType === '<>') { start = '<'; end = '>'; }
    const quoted = input.split('\n').map(line => `${start}${line}${end}`).join('\n');
    setInput(quoted);
  };

  const handleAddAtLocation = (isPrefix: boolean) => {
    if (!extraContent) return;
    saveToHistory();
    const processed = input.split('\n').map(line => isPrefix ? extraContent + line : line + extraContent).join('\n');
    setInput(processed);
  };

  const handleTrimLines = () => {
    saveToHistory();
    setInput(input.split('\n').map(line => line.trim()).join('\n'));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setInput(previous);
  };

  const handleCopy = () => {
    if (!input) return;
    navigator.clipboard.writeText(input);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const renderedMarkdown = useMemo(() => {
    if (!debouncedInput || !isPreview || typeof marked === 'undefined') return '';
    try {
        return marked.parse(debouncedInput, { breaks: true, gfm: true });
    } catch (e) {
        return 'Error parsing markdown';
    }
  }, [debouncedInput, isPreview]);

  return (
    <div className="flex flex-col gap-6 h-full">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex items-center gap-2 shrink-0">
            <IconType className="w-5 h-5 text-primary-400" />
            <h2 className="text-xl font-bold text-slate-100">{t.title}</h2>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setIsPreview(!isPreview)} className={`flex items-center gap-2 px-3 py-1.5 text-xs font-medium border rounded transition-all shadow-sm ${isPreview ? 'bg-primary-600 border-primary-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-300 hover:text-white hover:bg-slate-700'}`}>
                {isPreview ? <IconCode className="w-3.5 h-3.5" /> : <IconMarkdown className="w-3.5 h-3.5" />}
                {isPreview ? t.editor : t.preview}
            </button>
            <button onClick={handleUndo} disabled={history.length === 0} className={`flex items-center gap-2 px-3 py-1.5 text-xs font-medium border rounded transition-all ${history.length > 0 ? 'bg-slate-800 border-slate-700 text-slate-300 hover:text-white hover:bg-slate-700' : 'bg-slate-900 border-slate-800 text-slate-600 cursor-not-allowed'}`}>
                <IconUndo className="w-3.5 h-3.5" /> {t.undo}
            </button>
            <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium bg-slate-800 border border-slate-700 rounded text-slate-300 hover:text-white hover:bg-slate-700 transition-all shadow-sm">
                {copied ? <IconCheck className="w-3.5 h-3.5" /> : <IconCopy className="w-3.5 h-3.5" />}
                {copied ? t.copied : t.copy}
            </button>
            <button onClick={() => { saveToHistory(); setInput(''); }} className="px-3 py-1.5 text-xs font-medium bg-red-900/20 border border-red-900/30 text-red-400 rounded hover:bg-red-900/30 transition-all">
                {t.clear}
            </button>
        </div>
      </div>
      <div className="flex-1 flex flex-col gap-4 min-h-0">
          <div className="flex flex-wrap items-center gap-3">
              <button onClick={handleUnescapeNewlines} className="flex-none flex items-center justify-center gap-2 px-4 py-2 h-9 text-xs font-bold bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 rounded-lg transition-all"><IconZap className="w-3.5 h-3.5 text-yellow-500" /> {t.unescapeN}</button>
              <button onClick={handleUnescapeQuotes} className="flex-none flex items-center justify-center gap-2 px-4 py-2 h-9 text-xs font-bold bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 rounded-lg transition-all"><IconZap className="w-3.5 h-3.5 text-blue-500" /> {t.unescapeQ}</button>
              <button onClick={handleTrimLines} className="flex-none px-4 py-2 h-9 text-xs font-bold bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 rounded-lg transition-all">{t.trimLines}</button>
              <div className="flex-none flex items-center gap-1 bg-slate-800/50 p-1 rounded-lg border border-slate-700/50">
                  <div className="w-16 relative">
                    <select value={quoteType} onChange={(e) => setQuoteType(e.target.value)} className="w-full h-7 bg-slate-800 border border-slate-700 rounded pl-2 pr-6 text-xs text-slate-200 outline-none focus:ring-1 focus:ring-primary-500 appearance-none font-mono cursor-pointer">
                        <option value='"'>" "</option><option value="'">' '</option><option value="`">` `</option><option value="[]">[ ]</option><option value="{}">{ }</option><option value="()"> ( ) </option><option value="<>">&lt; &gt;</option>
                    </select>
                    <div className="absolute right-1 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500"><IconChevronDown className="w-3 h-3" /></div>
                  </div>
                  <button onClick={handleQuoteLines} className="px-3 h-7 text-xs font-bold bg-indigo-600 hover:bg-indigo-500 text-white rounded transition-all whitespace-nowrap">{t.wrap}</button>
              </div>
              <div className="flex-none w-full sm:w-auto max-w-sm flex items-center gap-1.5 bg-slate-800/50 p-1 rounded-lg border border-slate-700/50">
                  <input type="text" value={extraContent} onChange={(e) => setExtraContent(e.target.value)} placeholder={t.extraPh} className="flex-1 min-w-[120px] h-7 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-xs text-slate-200 outline-none focus:ring-1 focus:ring-primary-500" />
                  <button onClick={() => handleAddAtLocation(true)} className="px-3 h-7 text-xs font-bold bg-primary-600 hover:bg-primary-500 text-white rounded transition-all">{t.appendPrefix}</button>
                  <button onClick={() => handleAddAtLocation(false)} className="px-3 h-7 text-xs font-bold bg-primary-600 hover:bg-primary-500 text-white rounded transition-all">{t.appendSuffix}</button>
              </div>
          </div>
          <div className="flex-1 relative bg-slate-800 rounded-xl border border-slate-700 overflow-hidden shadow-inner flex flex-col">
            {!isPreview ? (
                <textarea value={input} onChange={(e) => setInput(e.target.value)} placeholder={t.placeholder} className="absolute inset-0 w-full h-full bg-transparent p-4 font-mono text-sm text-slate-200 resize-none outline-none focus:ring-2 focus:ring-primary-500/20" spellCheck="false" />
            ) : (
                <div className="absolute inset-0 w-full h-full overflow-auto p-6 md:p-8 bg-slate-950/40">
                    <style>{`
                        .md-preview h1 { font-size: 2.25rem !important; font-weight: 800 !important; color: white !important; margin-top: 2rem !important; margin-bottom: 1.5rem !important; border-bottom: 2px solid #334155 !important; padding-bottom: 0.75rem !important; }
                        .md-preview h2 { font-size: 1.5rem !important; font-weight: 700 !important; color: white !important; margin-top: 2rem !important; margin-bottom: 1rem !important; border-bottom: 1px solid #1e293b !important; padding-bottom: 0.5rem !important; }
                        .md-preview p { color: #cbd5e1 !important; line-height: 1.75 !important; margin-bottom: 1rem !important; }
                    `}</style>
                    <div className="md-preview prose prose-invert max-w-none prose-p:text-slate-300 prose-p:leading-7 prose-p:mb-4 prose-a:text-primary-400 prose-code:bg-slate-900 prose-code:text-emerald-400 prose-code:px-1.5 prose-code:rounded prose-pre:bg-slate-900 prose-pre:border prose-pre:border-slate-800" dangerouslySetInnerHTML={{ __html: renderedMarkdown }} />
                    {!input && <div className="text-slate-600 italic text-center mt-20">{lang === 'zh' ? '暂无内容可预览' : 'No content to preview'}</div>}
                </div>
            )}
          </div>
      </div>
      <div className="flex items-center gap-4 text-[10px] text-slate-500 uppercase tracking-widest font-bold">
          <div className="flex gap-1.5 items-center"><span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>{lang === 'zh' ? '行数' : 'Lines'}: {input ? input.split('\n').length : 0}</div>
          <div className="flex gap-1.5 items-center"><span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span>{lang === 'zh' ? '字符数' : 'Chars'}: {input.length}</div>
          <div className="flex gap-1.5 items-center"><span className="w-1.5 h-1.5 rounded-full bg-indigo-500"></span>{lang === 'zh' ? '历史' : 'History'}: {history.length}/20</div>
      </div>
    </div>
  );
};

